<template>
    <div class="tiptap-toolbar d-flex align-items-center mb-4 pb-3 border-bottom flex-wrap">
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0"
            @click="editor && editor.chain().focus().undo().run()" :disabled="!canUndo()">
            <CIcon name="cil-action-undo" size="sm" />
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0 mr-1"
            @click="editor && editor.chain().focus().redo().run()" :disabled="!canRedo()">
            <CIcon name="cil-action-redo" size="sm" />
        </CButton>

        <div class="toolbar-divider"></div>

        <CDropdown color="light" class="toolbar-dropdown mr-1" toggler-text="H">
            <CDropdownItem @click="$emit('insert-text-block')">Insert Text Block</CDropdownItem>
            <CDropdownItem divider></CDropdownItem>
            <CDropdownItem @click="editor && editor.chain().focus().setParagraph().run()"
                :class="{ 'text-primary font-weight-bold': isActive('paragraph') }">Paragraph
            </CDropdownItem>
            <CDropdownItem @click="editor && editor.chain().focus().toggleHeading({ level: 1 }).run()"
                :class="{ 'text-primary font-weight-bold': isActive('heading', { level: 1 }) }">Heading 1
            </CDropdownItem>
            <CDropdownItem @click="editor && editor.chain().focus().toggleHeading({ level: 2 }).run()"
                :class="{ 'text-primary font-weight-bold': isActive('heading', { level: 2 }) }">Heading 2
            </CDropdownItem>
            <CDropdownItem @click="editor && editor.chain().focus().toggleHeading({ level: 3 }).run()"
                :class="{ 'text-primary font-weight-bold': isActive('heading', { level: 3 }) }">Heading 3
            </CDropdownItem>
        </CDropdown>

        <CDropdown color="light" class="toolbar-dropdown mr-1" toggler-text="List">
            <CDropdownItem @click="editor && editor.chain().focus().toggleBulletList().run()"
                :class="{ 'text-primary font-weight-bold': isActive('bulletList') }">
                <CIcon name="cil-list" size="sm" class="mr-2" /> Bullet List
            </CDropdownItem>
            <CDropdownItem @click="editor && editor.chain().focus().toggleOrderedList().run()"
                :class="{ 'text-primary font-weight-bold': isActive('orderedList') }">
                <CIcon name="cil-list-numbered" size="sm" class="mr-2" /> Ordered List
            </CDropdownItem>
        </CDropdown>

        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0 mr-1"
            :class="{ 'active': isActive('blockquote') }"
            @click="editor && editor.chain().focus().toggleBlockquote().run()">
            <CIcon name="cil-double-quote-sans-left" size="sm" />
        </CButton>

        <div class="toolbar-divider"></div>

        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0" :class="{ 'active': isActive('bold') }"
            @click="editor && editor.chain().focus().toggleBold().run()">
            <strong>B</strong>
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0" style="font-style: italic;"
            :class="{ 'active': isActive('italic') }" @click="editor && editor.chain().focus().toggleItalic().run()">
            <em>I</em>
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0" :class="{ 'active': isActive('strike') }"
            @click="editor && editor.chain().focus().toggleStrike().run()">
            <del>S</del>
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0" :class="{ 'active': isActive('code') }"
            @click="editor && editor.chain().focus().toggleCode().run()">&lt;/&gt;
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0" :class="{ 'active': isActive('underline') }"
            @click="editor && editor.chain().focus().toggleUnderline().run()">
            <u>U</u>
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0" :class="{ 'active': isActive('highlight') }"
            @click="editor && editor.chain().focus().toggleHighlight().run()">
            <CIcon name="cil-color-palette" size="sm" />
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0 mr-1" :class="{ 'active': isActive('link') }"
            @click="setLink">
            <CIcon name="cil-link" size="sm" />
        </CButton>

        <div class="toolbar-divider"></div>

        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0"
            :class="{ 'active': isActive('superscript') }"
            @click="editor && editor.chain().focus().toggleSuperscript().run()">
            x²
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0 mr-1"
            :class="{ 'active': isActive('subscript') }"
            @click="editor && editor.chain().focus().toggleSubscript().run()">
            x₂
        </CButton>

        <div class="toolbar-divider"></div>

        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0"
            :class="{ 'active': isActive({ textAlign: 'left' }) }"
            @click="editor && editor.chain().focus().setTextAlign('left').run()">
            <CIcon name="cil-align-left" size="sm" />
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0"
            :class="{ 'active': isActive({ textAlign: 'center' }) }"
            @click="editor && editor.chain().focus().setTextAlign('center').run()">
            <CIcon name="cil-align-center" size="sm" />
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0"
            :class="{ 'active': isActive({ textAlign: 'right' }) }"
            @click="editor && editor.chain().focus().setTextAlign('right').run()">
            <CIcon name="cil-align-right" size="sm" />
        </CButton>
        <CButton color="light" size="sm" class="toolbar-btn px-2 border-0 mr-1"
            :class="{ 'active': isActive({ textAlign: 'justify' }) }"
            @click="editor && editor.chain().focus().setTextAlign('justify').run()">
            <CIcon name="cil-justify-center" size="sm" />
        </CButton>

        <div class="toolbar-divider"></div>

        <CDropdown color="light" class="toolbar-dropdown mr-1 border-0" toggler-text="+ Add">
            <CDropdownItem @click="insertVariable('{StudentName}')">Student Name Variable</CDropdownItem>
            <CDropdownItem @click="insertVariable('{StudentID}')">Student ID Variable</CDropdownItem>
            <CDropdownItem @click="insertVariable('{School}')">School Variable</CDropdownItem>
            <CDropdownItem @click="insertVariable('{Program}')">Program Variable</CDropdownItem>
            <CDropdownItem @click="insertVariable('{AcademyYear}')">Academy Year Variable</CDropdownItem>
            <CDropdownItem divider></CDropdownItem>
            <CDropdownItem @click="triggerFileInput">Upload Image</CDropdownItem>
        </CDropdown>
        <input type="file" ref="imageUpload" accept="image/*" class="d-none" @change="handleImageUpload">
    </div>
</template>

<script>
export default {
    name: 'EditorToolbar',
    props: {
        editor: { type: Object, required: false }
    },
    methods: {
        isActive(name, opts) {
            if (!this.editor || !this.editor.isActive) return false
            try {
                return this.editor.isActive(name, opts)
            } catch (e) {
                return false
            }
        },
        canUndo() {
            if (!this.editor || !this.editor.can) return false
            try {
                return this.editor.can().chain().focus().undo().run()
            } catch (e) {
                return false
            }
        },
        canRedo() {
            if (!this.editor || !this.editor.can) return false
            try {
                return this.editor.can().chain().focus().redo().run()
            } catch (e) {
                return false
            }
        },
        insertVariable(variableStr) {
            if (!this.editor) return
            this.editor.chain().focus().insertContent(variableStr).run()
        },
        triggerFileInput() {
            this.$refs.imageUpload.click()
        },
        handleImageUpload(event) {
            const file = event.target.files[0]
            if (!file) return
            const reader = new FileReader()
            reader.onload = (e) => {
                // emit the image data URL so the parent editor (Konva) can handle insertion
                this.$emit('image-uploaded', e.target.result)
                event.target.value = ''
            }
            reader.readAsDataURL(file)
        },
        setLink() {
            if (!this.editor) return
            const previousUrl = (this.editor.getAttributes && this.editor.getAttributes('link')) ? this.editor.getAttributes('link').href : ''
            const url = window.prompt('URL', previousUrl)
            if (url === null) return
            if (url === '') {
                this.editor.chain().focus().extendMarkRange('link').unsetLink().run()
                return
            }
            this.editor.chain().focus().extendMarkRange('link').setLink({ href: url }).run()
        }
    }
}
</script>

<style scoped>
.tiptap-toolbar .toolbar-btn {
    background-color: transparent !important;
    border: none !important;
    color: #4b5563 !important;
    box-shadow: none !important;
    font-size: 15px;
    padding: 6px 10px;
}

.tiptap-toolbar .toolbar-btn.active {
    background-color: #f3f4f6 !important;
    color: #4f46e5 !important;
    border-radius: 6px;
}

.tiptap-toolbar .toolbar-btn:hover {
    background-color: #f3f4f6 !important;
    color: #111827 !important;
    border-radius: 6px;
}

.toolbar-divider {
    width: 1px;
    height: 24px;
    background-color: #e5e7eb;
    margin: 0 10px;
}

::v-deep .tiptap-toolbar .toolbar-dropdown .dropdown-toggle {
    background-color: transparent !important;
    border: none !important;
    color: #4b5563 !important;
    font-weight: 500;
    font-size: 14px;
    border-radius: 6px;
    padding: 6px 12px;
    box-shadow: none !important;
}

::v-deep .tiptap-toolbar .toolbar-dropdown .dropdown-toggle:hover {
    background-color: #f3f4f6 !important;
    color: #111827 !important;
}
</style>
